import './VerticalContent.scss';

import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../../../helpers/classnames';
import { Typography } from '../../../Typography';
import { TimelineAtom } from '../../TimelineAtom';
import type { VerticalContentProps } from './VerticalContent.types';

export const VerticalContent: FC<VerticalContentProps> = ({
	id,
	type,
	position,
	title,
	text,
	signature,
	action,
	collapsable = false,
	collapsed = false,
	iconName,
}) => {
	const variant = type === 'active' || type === 'inactive' ? 'body2' : 'subtitle2';

	return (
		<li data-testid="VerticalContent" key={id} className="dsb-timeline__vertical" role="listitem">
			<TimelineAtom
				type={type}
				position={position}
				direction="vertical"
				collapsable={collapsable}
				collapsed={collapsed}
				iconName={iconName}
			/>

			<div className="dsb-timeline-body">
				<div className={classNames('dsb-timeline-body-title', `dsb-timeline-body-title__${type}`)}>
					{title && (
						<Typography
							variant={variant}
							className={classNames('dsb-timeline-body-title-name', `dsb-timeline-body-title-name__${type}`)}
						>
							{title}
						</Typography>
					)}

					{signature && (
						<Typography
							variant="caption"
							className={classNames('dsb-timeline-body-title-signature', `dsb-timeline-body-title-signature__${type}`)}
						>
							{signature}
						</Typography>
					)}
				</div>

				{text && (
					<Typography
						variant="body3"
						className={classNames('dsb-timeline-body-text', `dsb-timeline-body-text__${type}`)}
					>
						{text}
					</Typography>
				)}

				{(type === 'current' || type === 'error') && <div className="dsb-timeline-body-action">{action}</div>}
			</div>
		</li>
	);
};
